-- 6. Tonbridge & Malling × Social Media Setup
INSERT INTO public.local_content (service_slug, town_slug, intro_paragraph, local_context, competition_landscape, success_approach, local_stats, pain_points, solutions, faqs, layout_variant)
VALUES (
  'social-media-setup',
  'tonbridge-and-malling',
  'Social media across Tonbridge and Malling operates through a patchwork of community groups that map to the borough''s distinct towns. Tonbridge has its own active Facebook groups where residents request recommendations daily. Kings Hill''s community groups blend residential and business networking. West Malling, Borough Green, Snodland, and Aylesford each maintain separate community pages where local businesses are discussed, recommended, and evaluated. A business that wants to be visible across the full borough needs to engage with multiple community networks, and that starts with properly set up, consistently branded social media profiles that are ready to convert any recommendation into an enquiry. Most businesses here have either no social presence or dormant profiles that create a worse impression than having nothing at all. We build and optimise your social media profiles for the multi-town reality of Tonbridge and Malling.',
  'Tonbridge and Malling''s social media landscape mirrors the borough''s town-by-town structure. Each major settlement has Facebook community groups where recommendation requests generate genuine business. Tonbridge is particularly active, with thousands of members in local groups. Kings Hill blends community discussion with business networking on both Facebook and LinkedIn. Instagram drives engagement for hospitality, lifestyle, and retail businesses, particularly those in Tonbridge and West Malling. LinkedIn is significant for the Kings Hill professional community. The borough council and local media share content that businesses can engage with to build visibility.',
  'Social media maturity varies dramatically across the borough. Kings Hill businesses tend to have LinkedIn presence but neglect Facebook. Tonbridge High Street retailers are more active on Facebook and Instagram but often lack consistency. Businesses in Snodland, Borough Green, and Aylesford are generally underrepresented on social media. Very few businesses maintain consistent branding and active profiles across multiple platforms targeting the full borough.',
  'We set up social media for Tonbridge and Malling businesses based on where each town''s audience engages. Trades targeting homeowners across the borough get Facebook profiles optimised for every community group from Tonbridge to Snodland. Kings Hill professional services get LinkedIn company pages built for B2B credibility. Hospitality and lifestyle businesses in Tonbridge and West Malling get Instagram profiles designed to showcase quality. Every profile is branded consistently for recognition across the borough.',
  '{"population": 132000, "growth": "Active community groups in every town across the borough", "business_districts": ["Tonbridge", "Kings Hill", "West Malling", "Aylesford", "Snodland", "Borough Green"], "key_fact": "Each town has separate community groups — borough-wide visibility requires multi-group presence"}',
  '[{"title": "Missing from community group recommendations across the borough", "description": "When a Tonbridge resident asks for a plumber recommendation, or a Kings Hill homeowner requests a gardener, businesses without social media profiles are invisible. These recommendation requests happen in separate groups for each town across the borough, and without profiles, your business cannot be tagged or found."}, {"title": "Dormant profiles undermining credibility in active communities", "description": "A Facebook page last updated twelve months ago tells Tonbridge and Malling residents that your business is either closed or disengaged. In communities where social media activity signals reliability, a neglected profile is worse than having no profile at all."}, {"title": "No LinkedIn presence for Kings Hill B2B opportunities", "description": "Kings Hill''s professional community evaluates potential suppliers and partners on LinkedIn. A business targeting the B2B market at Kings Hill without a polished LinkedIn company page is invisible to decision-makers who research suppliers before making contact."}]',
  '[{"title": "Multi-town Facebook setup for borough-wide visibility", "description": "We build and optimise your Facebook business profile for engagement across every community group in Tonbridge and Malling. Professional branding, complete service area information, and content templates ensure your business can be recommended and found whether the conversation is happening in a Tonbridge, Snodland, or Borough Green group."}, {"title": "LinkedIn company page for Kings Hill B2B positioning", "description": "For businesses targeting the Kings Hill corporate market, we build LinkedIn pages that project professional authority. Company overview, service descriptions, and team profiles are optimised to convert the LinkedIn research that Kings Hill decision-makers conduct before engaging suppliers."}, {"title": "Consistent cross-platform branding across the borough", "description": "Same logo, colours, contact details, and messaging across Facebook, Instagram, LinkedIn, and Google Business Profile. We ensure your Tonbridge and Malling business looks identical on every platform, building the recognition and trust that drives conversions from social media across the borough."}]',
  '[{"question": "Which platforms should my Tonbridge and Malling business use?", "answer": "For trades and home services, Facebook is essential due to the borough''s active community groups. For Kings Hill B2B, LinkedIn is primary. For hospitality and lifestyle businesses in Tonbridge and West Malling, Instagram drives engagement. We recommend the right platforms based on your specific audience and service area."}, {"question": "Do you manage social media or just set it up?", "answer": "This service covers professional setup: creating, branding, and optimising your profiles for the Tonbridge and Malling market. We provide content templates and posting guides for ongoing maintenance. Continuous management is available as a separate service if you prefer a hands-off approach."}, {"question": "How do I engage with multiple town community groups?", "answer": "We set up your profiles so they are ready for engagement in every relevant group across the borough. Professional branding, portfolio content, and service area information ensure that when you respond to a recommendation request in any town''s group, your profile converts interest into enquiries."}, {"question": "Should I have separate profiles for different areas of the borough?", "answer": "No. One strong, well-branded profile per platform is better than multiple fragmented ones. We ensure your single profile is optimised to serve the entire borough, with service area coverage clearly indicating that you serve Tonbridge, Kings Hill, West Malling, and all surrounding areas."}]',
  'trust'
)
